import{_ as e,c as s,o as n,a}from"./app.89058f37.js";const m=JSON.parse('{"title":"为什么是 vite","description":"","frontmatter":{},"headers":[{"level":2,"title":"优势","slug":"优势","link":"#优势","children":[{"level":3,"title":"快","slug":"快","link":"#快","children":[]},{"level":3,"title":"配置","slug":"配置","link":"#配置","children":[]},{"level":3,"title":"文档","slug":"文档","link":"#文档","children":[]}]},{"level":2,"title":"劣势","slug":"劣势","link":"#劣势","children":[{"level":3,"title":"生态","slug":"生态","link":"#生态","children":[]},{"level":3,"title":"环境","slug":"环境","link":"#环境","children":[]}]},{"level":2,"title":"总结","slug":"总结","link":"#总结","children":[]}],"relativePath":"blogs/2022/why-vite.md","lastUpdated":1672409436000}'),l={name:"blogs/2022/why-vite.md"},d=a('<h1 id="为什么是-vite" tabindex="-1">为什么是 vite <a class="header-anchor" href="#为什么是-vite" aria-hidden="true">#</a></h1><p>2022 年我做过最疯狂的事是 <del>疯狂给 <code>uni-app</code> 提 issue</del> <del>疯狂做 <code>uni-app</code> 生态</del> 把几个项目从 <code>webpack</code> 迁移到 <code>vite</code>。</p><p>必须先声明的是，<code>webpack</code> 真的很强大，与此同时它也很复杂。我之前有写过一篇 webpack 4 教程，但遗憾的是我完全没有精力再出一篇 webpack 5 教程。</p><p>抛开现实生活中的影响，我认为 <code>webpack</code> 复杂的配置项和排列组合在很大程度上劝退了我。内置外置的 loader，这种那种的 plugin，足以把我绕晕，更别提模块联邦了。</p><p><code>vite</code> 出现之后，我几乎毫不犹豫地投入了 <code>vite</code> 阵营。</p><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-hidden="true">#</a></h2><h3 id="快" tabindex="-1">快 <a class="header-anchor" href="#快" aria-hidden="true">#</a></h3><p><code>vite</code> 的启动和更新非常快。在我这里，同样的项目，<code>vite</code> 所需的时间是 <code>webpack</code> 的 1/5 - 1/2。这可以说是一个巨大的飞跃了。</p><p>即使我需要支持传统浏览器，<code>vite</code> 所需的时间也比 <code>webpack</code> 少了至少 1/10。</p><h3 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-hidden="true">#</a></h3><p>尽管我认为 <code>vite</code> 的配置还是很多，但我也不得不承认，相比起 <code>webpack</code> 它已经简化了很多。</p><p>似乎也已经很难再缩减配置项了，因为前端的构建复杂度也在逐渐增加，包括 SSR、ESM 等。值得一提的是，<code>vite</code> 也有 SSR 支持。</p><h3 id="文档" tabindex="-1">文档 <a class="header-anchor" href="#文档" aria-hidden="true">#</a></h3><p><code>vite</code> 的文档和 <code>vue</code> 的文档类似，读起来非常舒服，而且也足够详细。<code>webpack</code> 的文档读起来差了点意思，有时候我甚至怀疑是不是我太笨了读不懂 <code>webpack</code> 文档，又或者是我是不是看漏了哪里。</p><h2 id="劣势" tabindex="-1">劣势 <a class="header-anchor" href="#劣势" aria-hidden="true">#</a></h2><h3 id="生态" tabindex="-1">生态 <a class="header-anchor" href="#生态" aria-hidden="true">#</a></h3><p><code>vite</code> 诞生至今时间不长，总体生态不如 <code>webpack</code>。可以说，<code>webpack</code> 已经把 99.9999% 的坑踩了一遍，而 <code>vite</code> 可能还需要再踩一遍。</p><p>庆幸的是，到现在我还没有遇到严重的大坑。</p><h3 id="环境" tabindex="-1">环境 <a class="header-anchor" href="#环境" aria-hidden="true">#</a></h3><p>在 v3 的改动日志中说得很清楚，这里照搬一下。</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark has-diff"><code><span class="line"><span style="color:#c9d1d9;">Experimental</span></span>\n<span class="line"><span style="color:#c9d1d9;"></span></span>\n<span class="line"><span style="color:#c9d1d9;">Using esbuild deps optimization at build time</span></span>\n<span class="line"><span style="color:#c9d1d9;"></span></span>\n<span class="line"><span style="color:#c9d1d9;">In v3, Vite allows the use of esbuild to optimize dependencies during build time. If enabled, it removes one of the most significant differences between dev and prod present in v2. `@rollup/plugin-commonjs` is no longer needed in this case since esbuild converts CJS-only dependencies to ESM.</span></span>\n<span class="line"><span style="color:#c9d1d9;"></span></span>\n<span class="line"><span style="color:#c9d1d9;">If you want to try this build strategy, you can use `optimizeDeps.disabled: false` (the default in v3 is `disabled: &#39;build&#39;`). `@rollup/plugin-commonjs` can be removed by passing `build.commonjsOptions: { include: [] }`.</span></span>\n<span class="line"><span style="color:#c9d1d9;"></span></span>\n<span class="line"><span style="color:#c9d1d9;">实验性功能</span></span>\n<span class="line"><span style="color:#c9d1d9;"></span></span>\n<span class="line"><span style="color:#c9d1d9;">在构建时使用 esbuild 优化依赖</span></span>\n<span class="line"><span style="color:#c9d1d9;"></span></span>\n<span class="line"><span style="color:#c9d1d9;">在 v3，Vite 允许在构建时使用 esbuild 来优化依赖关系。如果启用，它将消除 v2 中存在的开发环境和生产环境之间最显著的差异之一。在这种情况下，不再需要 `@rollup/plugin-commonjs`，因为 `esbuild` 将仅有的 CJS 依赖关系转换为 ESM。</span></span>\n<span class="line"><span style="color:#c9d1d9;"></span></span>\n<span class="line"><span style="color:#c9d1d9;">如果你想尝试这种构建策略，你可以使用 `optimizeDeps.disabled: false`（v3 默认为 `disabled: &#39;build&#39;`）。`@rollup/plugin-commonjs` 可以通过传递 `build.commonjsOptions: { include: [] }` 来移除。</span></span>\n<span class="line"><span style="color:#c9d1d9;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-hidden="true">#</a></h2><p><code>vite</code> 很有潜力。我已经顶不住 <code>webpack</code> 了，所以我转投了 <code>vite</code> 阵营。我很满意 <code>vite</code> 的表现。希望你也会喜欢。</p>',23),c=[d];function i(p,o,t,r,b,h){return n(),s("div",null,c)}const v=e(l,[["render",i]]);export{m as __pageData,v as default};
